            <circle cx="65" cy="45" r="5" fill="#1565C0" />
            <circle cx="37" cy="43" r="2" fill="white" />
            <circle cx="67" cy="43" r="2" fill="white" />
            <circle cx="25" cy="60" r="8" fill="#FFCDD2" opacity="0.5"/>
            <circle cx="75" cy="60" r="8" fill="#FFCDD2" opacity="0.5"/>
